1	package bead
2	
3	import (
4		"fmt"
5		"time"
6	)
7	
8	// BeadsArchiveCollection is the logical collection name for archived beads.
9	// It is registered in the default registry alongside the active "beads"
10	// collection and is backed by .ddx/beads-archive.jsonl in the JSONL backend.
11	const BeadsArchiveCollection = "beads-archive"
12	
13	// ArchivePolicy parameterises which closed beads are eligible to move from
14	// the active collection to the archive. Defaults match TD-027 §(b).
15	type ArchivePolicy struct {
16		// Statuses lists the bead statuses that are eligible for archival.
17		Statuses []string
18		// MinAge is the minimum time since a bead was last updated/closed
19		// before it may be archived.
20		MinAge time.Duration
21		// MinActiveCount is the floor on active-collection size below which
22		// archival is a no-op. Set to 0 to archive regardless of size.
23		MinActiveCount int
24		// BatchSize caps how many records move per call.
25		BatchSize int
26	}
27	
28	// DefaultArchivePolicy returns the shipping defaults from TD-027 §(b).
29	func DefaultArchivePolicy() ArchivePolicy {
30		return ArchivePolicy{
31			Statuses:       []string{StatusClosed},
32			MinAge:         30 * 24 * time.Hour,
33			MinActiveCount: 2000,
34			BatchSize:      500,
35		}
36	}
37	
38	// archivePartner returns a Store for the beads-archive collection rooted at
39	// the same .ddx directory as s. The partner reuses the shipping registry
40	// spec for "beads-archive" so file/lock paths are uniform.
41	func (s *Store) archivePartner() *Store {
42		return NewStoreWithCollection(s.Dir, BeadsArchiveCollection)
43	}
44	
45	// Archive moves eligible closed beads from this active store to the
46	// beads-archive partner. It applies preserve_dependencies semantics from
47	// TD-027 §(b): a closed bead that an open or in_progress bead still
48	// references is retained in the active collection so SD-004 queue
49	// derivation can resolve it without loading the archive.
50	//
51	// Returns the IDs that were moved.
52	func (s *Store) Archive(policy ArchivePolicy) ([]string, error) {
53		if s.Collection != DefaultCollection {
54			return nil, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
55		}
56		archive := s.archivePartner()
57	
58		var moved []string
59		// Lock order is fixed: active first, archive second, per TD-027 §(b).
60		err := s.WithLock(func() error {
61			return archive.WithLock(func() error {
62				activeBeads, _, rerr := s.readAllLatestRaw()
63				if rerr != nil {
64					return rerr
65				}
66				if policy.MinActiveCount > 0 && len(activeBeads) < policy.MinActiveCount {
67					return nil
68				}
69	
70				// preserve_dependencies: skip closed beads still referenced by
71				// any non-closed bead's dependency list.
72				referenced := make(map[string]bool)
73				for _, b := range activeBeads {
74					if b.Status == StatusClosed {
75						continue
76					}
77					for _, dep := range b.DepIDs() {
78						referenced[dep] = true
79					}
80				}
81	
82				now := time.Now().UTC()
83				eligible := make(map[string]bool)
84				var toMove []Bead
85				for _, b := range activeBeads {
86					if !containsString(policy.Statuses, b.Status) {
87						continue
88					}
89					if referenced[b.ID] {
90						continue
91					}
92					ts := b.UpdatedAt
93					if raw, ok := b.Extra["closed_at"].(string); ok {
94						if parsed, perr := time.Parse(time.RFC3339, raw); perr == nil {
95							ts = parsed
96						}
97					}
98					if policy.MinAge > 0 && now.Sub(ts) < policy.MinAge {
99						continue
100					}
101					toMove = append(toMove, b)
102					if policy.BatchSize > 0 && len(toMove) >= policy.BatchSize {
103						break
104					}
105				}
106				if len(toMove) == 0 {
107					return nil
108				}
109	
110				archiveBeads, _, aerr := archive.readAllLatestRaw()
111				if aerr != nil {
112					return aerr
113				}
114				archiveByID := make(map[string]int, len(archiveBeads))
115				for i, b := range archiveBeads {
116					archiveByID[b.ID] = i
117				}
118				stamp := now.Format(time.RFC3339)
119				for _, b := range toMove {
120					if b.Extra == nil {
121						b.Extra = make(map[string]any)
122					}
123					b.Extra["archived_at"] = stamp
124					eligible[b.ID] = true
125					if idx, ok := archiveByID[b.ID]; ok {
126						archiveBeads[idx] = b
127					} else {
128						archiveByID[b.ID] = len(archiveBeads)
129						archiveBeads = append(archiveBeads, b)
130					}
131				}
132	
133				// Step 7 of TD-027 mutation sequence: write archive first, then
134				// active. A crash between the two leaves a duplicate in both
135				// collections; merged-view reads in (e) hide that with
136				// active-wins precedence.
137				if werr := archive.WriteAll(archiveBeads); werr != nil {
138					return fmt.Errorf("bead: write archive: %w", werr)
139				}
140				remaining := make([]Bead, 0, len(activeBeads)-len(toMove))
141				for _, b := range activeBeads {
142					if eligible[b.ID] {
143						moved = append(moved, b.ID)
144						continue
145					}
146					remaining = append(remaining, b)
147				}
148				if werr := s.WriteAll(remaining); werr != nil {
149					return fmt.Errorf("bead: write active: %w", werr)
150				}
151				return nil
152			})
153		})
154		if err != nil {
155			return nil, err
156		}
157		return moved, nil
158	}
159	
160	// GetWithArchive resolves a bead ID across the active collection and the
161	// archive partner, with active-wins precedence. This is the lookup the
162	// `ddx bead show` command uses so a closed-and-archived bead remains
163	// addressable by ID.
164	func (s *Store) GetWithArchive(id string) (*Bead, error) {
165		if b, err := s.Get(id); err == nil {
166			return b, nil
167		}
168		if s.Collection != DefaultCollection {
169			return nil, fmt.Errorf("bead: not found: %s", id)
170		}
171		archive := s.archivePartner()
172		b, err := archive.Get(id)
173		if err != nil {
174			return nil, fmt.Errorf("bead: not found: %s", id)
175		}
176		return b, nil
177	}
178	
179	// ListWithArchive returns the union of active and archive beads filtered
180	// the same way as List. Active records take precedence over archive
181	// duplicates that may exist after an interrupted archive run.
182	func (s *Store) ListWithArchive(status, label string, where map[string]string) ([]Bead, error) {
183		active, err := s.List(status, label, where)
184		if err != nil {
185			return nil, err
186		}
187		if s.Collection != DefaultCollection {
188			return active, nil
189		}
190		archive := s.archivePartner()
191		archived, err := archive.List(status, label, where)
192		if err != nil {
193			// Archive may not exist yet — treat as empty.
194			return active, nil //nolint:nilerr
195		}
196		seen := make(map[string]bool, len(active))
197		out := make([]Bead, 0, len(active)+len(archived))
198		for _, b := range active {
199			seen[b.ID] = true
200			out = append(out, b)
201		}
202		for _, b := range archived {
203			if seen[b.ID] {
204				continue
205			}
206			out = append(out, b)
207		}
208		return out, nil
209	}
210	
211	// maybeOpportunisticArchive runs Archive() with default policy if the
212	// active set has crossed MinActiveCount. Errors are swallowed: archival is
213	// best-effort and must not fail a close-causing mutation. TD-027 §(b)
214	// enables this trigger after close mutations.
215	func (s *Store) maybeOpportunisticArchive() {
216		if s.Collection != DefaultCollection {
217			return
218		}
219		_, _ = s.Archive(DefaultArchivePolicy())
220	}
