71	// beadAutoCommit commits .ddx/beads.jsonl if git.auto_commit is "always".
72	// The operation string describes what happened (e.g. "create ddx-abc123").
73	// Errors are silently ignored — auto-commit is best-effort.
74	// When a commit lands, the resulting SHA is returned.
75	func (f *CommandFactory) beadAutoCommit(operation string) string {
76		workspaceRoot := f.beadWorkspaceRoot()
77		if workspaceRoot == "" {
78			workspaceRoot = f.WorkingDir
79		}
80	
81		cfg, err := config.LoadWithWorkingDir(workspaceRoot)
82		if err != nil {
83			return ""
84		}
85		if cfg.Git == nil {
86			return ""
87		}
88		acCfg := gitpkg.AutoCommitConfig{
89			AutoCommit:   cfg.Git.AutoCommit,
90			CommitPrefix: cfg.Git.CommitPrefix,
91		}
92		beadsFile := filepath.Join(workspaceRoot, ".ddx", "beads.jsonl")
93		sha, _ := gitpkg.AutoCommit(beadsFile, "beads", operation, acCfg)
94		return sha
95	}
96	
97	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
98		if commitSHA == "" {
99			return "", nil
100		}
101	
102		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
103		defer cancel()
104	
105		repoDir := f.WorkingDir
106		if repoDir == "" {
107			repoDir = "."
108		}
109	
110		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
111			return commitSHA, nil
112		}
113	
114		cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
115		out, err := cmd.Output()
116		if err != nil {
117			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
118		}
119		return strings.TrimSpace(string(out)), nil
120	}
121	
122	func isFullCommitSHA(commitSHA string) bool {
123		if len(commitSHA) != 40 {
124			return false
125		}
126		for i := 0; i < len(commitSHA); i++ {
127			c := commitSHA[i]
128			if c >= '0' && c <= '9' {
129				continue
130			}
131			if c >= 'a' && c <= 'f' {
132				continue
133			}
134			if c >= 'A' && c <= 'F' {
135				continue
136			}
137			return false
138		}
139		return true
140	}
141	
142	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
143		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
144		if err != nil {
145			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
146		}
147		if normalizedCommitSHA == "" {
148			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
149		}
150		return normalizedCommitSHA, nil
151	}
152	
153	// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
154	// only bead tracker state. Closing provenance is suppressed only for pure
155	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
156	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
157		if commitSHA == "" {
158			return false
159		}
160	
161		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
162		defer cancel()
163	
164		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
165		out, err := cmd.Output()
166		if err != nil {
167			return false
168		}
169	
170		for _, line := range strings.Split(string(out), "\n") {
171			path := strings.TrimSpace(line)
172			if path == "" {
173				continue
174			}
175			if path != ".ddx/beads.jsonl" {
176				return false
177			}
178		}
179	
180		return true
181	}
