183	func isReviewCloseBead(b *bead.Bead) bool {
184		if b == nil {
185			return false
186		}
187		for _, label := range b.Labels {
188			switch label {
189			case "action:review", "kind:review", "phase:review", "review-finding":
190				return true
191			}
192		}
193		return false
194	}
