196	func (f *CommandFactory) beadWorkspaceRoot() string {
197		dir := os.Getenv("DDX_BEAD_DIR")
198		if dir != "" {
199			if filepath.Base(dir) == ".ddx" {
200				return filepath.Dir(dir)
201			}
202			return dir
203		}
204		if f.WorkingDir == "" {
205			return ""
206		}
207		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
208			return workspaceRoot
209		}
210		return f.WorkingDir
211	}
