213	func (f *CommandFactory) beadStore() *bead.Store {
214		workspaceRoot := f.beadWorkspaceRoot()
215		if workspaceRoot == "" {
216			return bead.NewStore("")
217		}
218		return bead.NewStore(filepath.Join(workspaceRoot, ".ddx"))
219	}
