245	func (f *CommandFactory) newBeadCreateCommand() *cobra.Command {
246		cmd := &cobra.Command{
247			Use:   "create <title>",
248			Short: "Create a new bead",
249			Args:  cobra.ExactArgs(1),
250			RunE: func(cmd *cobra.Command, args []string) error {
251				s := f.beadStore()
252				b := &bead.Bead{Title: args[0]}
253	
254				if v, _ := cmd.Flags().GetString("type"); v != "" {
255					b.IssueType = v
256				}
257				if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
258					b.Priority = v
259				}
260				if v, _ := cmd.Flags().GetString("labels"); v != "" {
261					b.Labels = strings.Split(v, ",")
262				}
263				if v, _ := cmd.Flags().GetString("acceptance"); v != "" {
264					b.Acceptance = v
265				}
266				if v, _ := cmd.Flags().GetString("description"); v != "" {
267					b.Description = v
268				}
269				if v, _ := cmd.Flags().GetString("parent"); v != "" {
270					b.Parent = v
271				}
272				if setFlags, _ := cmd.Flags().GetStringArray("set"); len(setFlags) > 0 {
273					if b.Extra == nil {
274						b.Extra = make(map[string]any)
275					}
276					for _, kv := range setFlags {
277						k, v, ok := strings.Cut(kv, "=")
278						if !ok {
279							return fmt.Errorf("--set requires key=value format, got: %s", kv)
280						}
281						switch v {
282						case "true":
283							b.Extra[k] = true
284						case "false":
285							b.Extra[k] = false
286						default:
287							b.Extra[k] = v
288						}
289					}
290				}
291	
292				if err := s.Create(b); err != nil {
293					return err
294				}
295				f.beadAutoCommit("create " + b.ID)
296				fmt.Fprintf(cmd.OutOrStdout(), "%s\n", b.ID)
297				return nil
298			},
299		}
300	
301		cmd.Flags().String("type", "", "Bead type (task, bug, epic, chore)")
302		cmd.Flags().Int("priority", 2, "Priority (0=highest, 4=lowest)")
303		cmd.Flags().String("labels", "", "Comma-separated labels")
304		cmd.Flags().String("acceptance", "", "Acceptance criteria")
305		cmd.Flags().String("description", "", "Description")
306		cmd.Flags().String("parent", "", "Parent bead ID")
307		cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")
308	
309		return cmd
310	}
