312	func (f *CommandFactory) newBeadShowCommand() *cobra.Command {
313		cmd := &cobra.Command{
314			Use:   "show <id>",
315			Short: "Show a bead",
316			Args:  cobra.ExactArgs(1),
317			RunE: func(cmd *cobra.Command, args []string) error {
318				s := f.beadStore()
319				b, err := s.GetWithArchive(args[0])
320				if err != nil {
321					return err
322				}
323	
324				asJSON, _ := cmd.Flags().GetBool("json")
325				if asJSON {
326					// Externalized events live in a sidecar; inline them for the
327					// JSON view so consumers (and the `events` UI projection)
328					// see a single uniform shape.
329					if err := s.LoadEventsInline(b); err != nil {
330						return err
331					}
332					data, err := bead.MarshalBead(*b)
333					if err != nil {
334						return err
335					}
336					var obj map[string]any
337					if err := json.Unmarshal(data, &obj); err != nil {
338						return err
339					}
340					workspaceRoot := f.beadWorkspaceRoot()
341					if workspaceRoot == "" {
342						workspaceRoot = f.WorkingDir
343					}
344					metrics, err := beadMetricsFor(workspaceRoot, b.ID)
345					if err != nil {
346						return err
347					}
348					if metrics == nil {
349						metrics = &beadMetricsSummary{}
350					}
351					obj["metrics"] = metrics
352					enc := json.NewEncoder(cmd.OutOrStdout())
353					enc.SetIndent("", "  ")
354					return enc.Encode(obj)
355				}
356	
357				out := cmd.OutOrStdout()
358				fmt.Fprintf(out, "ID:       %s\n", b.ID)
359				fmt.Fprintf(out, "Title:    %s\n", b.Title)
360				fmt.Fprintf(out, "Type:     %s\n", b.IssueType)
361				fmt.Fprintf(out, "Status:   %s\n", b.Status)
362				fmt.Fprintf(out, "Priority: %d\n", b.Priority)
363				if len(b.Labels) > 0 {
364					fmt.Fprintf(out, "Labels:   %s\n", strings.Join(b.Labels, ", "))
365				}
366				if b.Owner != "" {
367					fmt.Fprintf(out, "Owner:    %s\n", b.Owner)
368				}
369				if b.Parent != "" {
370					fmt.Fprintf(out, "Parent:   %s\n", b.Parent)
371				}
372				if len(b.Dependencies) > 0 {
373					fmt.Fprintf(out, "Deps:     %s\n", strings.Join(b.DepIDs(), ", "))
374				}
375				if b.Description != "" {
376					fmt.Fprintf(out, "Desc:     %s\n", b.Description)
377				}
378				if b.Acceptance != "" {
379					fmt.Fprintf(out, "Accept:   %s\n", b.Acceptance)
380				}
381				fmt.Fprintf(out, "Created:  %s\n", b.CreatedAt.Format("2006-01-02 15:04:05"))
382				fmt.Fprintf(out, "Updated:  %s\n", b.UpdatedAt.Format("2006-01-02 15:04:05"))
383				// Show agent session evidence if present
384				if b.Extra != nil {
385					if sessionID, ok := b.Extra["session_id"]; ok && sessionID != "" {
386						fmt.Fprintf(out, "Session:  %v\n", sessionID)
387						// Try to resolve session details
388						if sess := f.resolveAgentSession(fmt.Sprint(sessionID)); sess != nil {
389							fmt.Fprintf(out, "Harness:  %s\n", sess.Harness)
390							if sess.Model != "" {
391								fmt.Fprintf(out, "Model:    %s\n", sess.Model)
392							}
393							if sess.Tokens > 0 {
394								fmt.Fprintf(out, "Tokens:   %d (in: %d, out: %d)\n", sess.Tokens, sess.InputTokens, sess.OutputTokens)
395							}
396							if sess.CostUSD > 0 {
397								fmt.Fprintf(out, "Cost:     $%.4f\n", sess.CostUSD)
398							}
399							if sess.Duration > 0 {
