439			Use:   "update <id>",
440			Short: "Update a bead",
441			Args:  cobra.ExactArgs(1),
442			RunE: func(cmd *cobra.Command, args []string) error {
443				s := f.beadStore()
444	
445				// --claim and --unclaim use dedicated store methods
446				if claim, _ := cmd.Flags().GetBool("claim"); claim {
447					assignee, _ := cmd.Flags().GetString("assignee")
448					if assignee == "" {
449						assignee = resolveClaimAssignee()
450					}
451					if err := s.Claim(args[0], assignee); err != nil {
452						return err
453					}
454					f.beadAutoCommit("claim " + args[0])
