456				}
457				if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
458					if err := s.Unclaim(args[0]); err != nil {
459						return err
460					}
461					f.beadAutoCommit("unclaim " + args[0])
462					return nil
463				}
464	
465				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
466					for _, key := range unsetFlags {
467						if isProtectedBeadExtraKey(key) {
468							return fmt.Errorf("cannot unset protected bead field: %s", key)
469						}
470					}
471				}
472	
473				var setFlags []string
474				if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
475					setFlags = make([]string, 0, len(rawSetFlags))
476					for _, kv := range rawSetFlags {
477						k, v, ok := strings.Cut(kv, "=")
478						if !ok {
479							return fmt.Errorf("--set requires key=value format, got: %s", kv)
480						}
481						if k == "closing_commit_sha" {
482							normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
483							if err != nil {
484								return err
485							}
486							v = normalizedCommitSHA
487						}
488						setFlags = append(setFlags, k+"="+v)
489					}
490				}
491	
492				if err := s.Update(args[0], func(b *bead.Bead) {
493					if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
494						b.Title = v
495					}
496					if v, _ := cmd.Flags().GetString("status"); cmd.Flags().Changed("status") {
497						b.Status = v
498					}
499					if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
500						b.Priority = v
501					}
502					if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
503						if v == "" {
504							b.Labels = []string{}
505						} else {
506							b.Labels = strings.Split(v, ",")
507						}
508					}
509					if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
510						b.Acceptance = v
511					}
512					if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
513						b.Owner = v
514					}
515					if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
516						b.Parent = v
517					}
518					if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
519						b.Description = v
520					}
521					if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
522						b.Notes = v
523					}
524					if len(setFlags) > 0 {
525						if b.Extra == nil {
526							b.Extra = make(map[string]any)
527						}
528						for _, kv := range setFlags {
529							k, v, ok := strings.Cut(kv, "=")
530							if !ok {
531								continue
532							}
533							// Route known field names to struct fields
534							switch k {
535							case "parent":
536								b.Parent = v
537							case "description":
538								b.Description = v
539							case "notes":
540								b.Notes = v
541							case "acceptance":
542								b.Acceptance = v
543							case "issue_type":
544								b.IssueType = v
545							default:
546								// Parse booleans and numbers for proper typing
547								switch v {
548								case "true":
549									b.Extra[k] = true
550								case "false":
551									b.Extra[k] = false
552								default:
553									b.Extra[k] = v
554								}
555							}
556						}
557					}
558					if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
559						for _, key := range unsetFlags {
560							if b.Extra != nil {
561								delete(b.Extra, key)
562							}
563						}
564					}
565				}); err != nil {
566					return err
567				}
568				f.beadAutoCommit("update " + args[0])
569				return nil
570			},
571		}
572	
573		cmd.Flags().String("title", "", "New title")
574		cmd.Flags().String("status", "", "New status (open, in_progress, closed)")
575		cmd.Flags().Int("priority", 0, "New priority")
576		cmd.Flags().String("labels", "", "New labels (comma-separated)")
577		cmd.Flags().String("acceptance", "", "New acceptance criteria")
