579		cmd.Flags().String("parent", "", "New parent bead ID")
580		cmd.Flags().String("description", "", "New description")
581		cmd.Flags().String("notes", "", "New notes")
582		cmd.Flags().Bool("claim", false, "Claim: set status=in_progress, assignee=ddx")
583		cmd.Flags().Bool("unclaim", false, "Unclaim: set status=open, clear assignee and claim fields")
584		cmd.Flags().StringArray("set", nil, "Set custom field (key=value, repeatable)")
