681	func (f *CommandFactory) newBeadCloseCommand() *cobra.Command {
682		cmd := &cobra.Command{
683			Use:   "close <id>",
684			Short: "Close a bead",
685			Args:  cobra.ExactArgs(1),
686			RunE: func(cmd *cobra.Command, args []string) error {
687				s := f.beadStore()
688				sessionID, _ := cmd.Flags().GetString("session")
689				commitSHA, _ := cmd.Flags().GetString("commit")
690	
691				if commitSHA != "" {
692					normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
693					if err != nil {
694						return err
695					}
696					commitSHA = normalizedCommitSHA
697				}
698	
699				target, err := s.Get(args[0])
700				if err != nil {
701					return err
702				}
703				// CloseWithEvidence runs the closure gate (ddx-e30e60a9); manual
704				// operator closes without evidence are intentionally a separate
705				// path. When --session and --commit are both unset, we are in
706				// manual-administration territory — use the ungated Store.Close
707				// so the gate doesn't reject legitimate tracker admin.
708				if sessionID == "" && commitSHA == "" {
709					if err := s.Close(args[0]); err != nil {
710						return err
711					}
712				} else if err := s.CloseWithEvidence(args[0], sessionID, commitSHA); err != nil {
713					return err
714				}
715	
716				landedSHA := f.beadAutoCommit("close " + args[0])
717				if commitSHA == "" && landedSHA != "" {
718					if f.commitIsMetadataOnlyTrackerBackfill(landedSHA) {
719						if isReviewCloseBead(target) {
720							// Tracker-only review-finding closes must not retain any prior
721							// replay boundary. The close commit itself is the metadata-only
722							// backfill, so clear stale closing provenance instead of
723							// preserving an unrelated implementation SHA.
724							if err := s.Update(args[0], func(b *bead.Bead) {
725								if b.Extra == nil {
726									return
727								}
728								delete(b.Extra, "closing_commit_sha")
729							}); err != nil {
730								return err
731							}
732							if followupSHA := f.beadAutoCommit("close " + args[0]); followupSHA == "" {
733								return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
734							}
735						}
736					} else {
737						// Only stamp closing provenance when the close commit includes
738						// real implementation work. Pure tracker backfills should not
739						// advertise a replay boundary that points at metadata-only
740						// provenance.
741						if err := s.Update(args[0], func(b *bead.Bead) {
742							if b.Extra == nil {
743								b.Extra = make(map[string]any)
744							}
745							b.Extra["closing_commit_sha"] = landedSHA
746						}); err != nil {
747							return err
748						}
749						if followupSHA := f.beadAutoCommit("close " + args[0]); followupSHA == "" {
750							return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
751						}
752					}
753				}
754				return nil
755			},
756		}
757		cmd.Flags().String("session", "", "Agent session ID that completed this bead")
758		cmd.Flags().String("commit", "", "Closing commit SHA (auto-detected if not provided)")
759		return cmd
760	}
